/**
 * Example: DEPIN Assets with AuthScript Addresses
 *
 * This example demonstrates how to use DEPIN assets with witness-v1 AuthScript
 * addresses generated by neurai-key.
 *
 * AuthScript address examples:
 * - Mainnet: nq1...
 * - Testnet: tnq1...
 */

const NeuraiAssets = require('@neuraiproject/neurai-assets');

async function createDepinForPQAddress() {
  const rpc = async (method, params) => {
    console.log(`RPC Call: ${method}`, params);
    // Replace with your actual RPC client
  };

  const assets = new NeuraiAssets(rpc, {
    network: 'xna',                             // Or 'xna-test'; xna-pq aliases are still accepted
    addresses: ['nq1yourauthscriptwalletaddress...'],
    changeAddress: 'nq1yourauthscriptchangeaddress...',
    toAddress: 'nq1recipientauthscriptaddress...'
  });

  try {
    const result = await assets.createDepinAsset({
      assetName: '&DEVICE/ROUTER001',
      quantity: 1,
      reissuable: false
    });

    console.log('DEPIN transaction created');
    console.log('Raw transaction:', result.rawTx);
    console.log('Burn:', result.burnAmount, 'XNA');
    console.log('Owner token:', result.ownerTokenName);
  } catch (error) {
    console.error('Error creating DEPIN asset for AuthScript address:', error.message);
  }
}

async function queryDepinValidityForPQAddress() {
  const rpc = async (method, params) => {
    console.log(`RPC Call: ${method}`, params);

    if (method === 'checkdepinvalidity') {
      return {
        has_asset: true,
        amount: 1,
        valid: 1,
        blocked: false
      };
    }

    if (method === 'listdepinholders') {
      return [
        { address: 'nq1firstholder...', amount: 1, valid: 1 },
        { address: 'nq1secondholder...', amount: 1, valid: 0 }
      ];
    }
  };

  const assets = new NeuraiAssets(rpc, {
    network: 'xna',
    addresses: ['nq1yourauthscriptwalletaddress...'],
    changeAddress: 'nq1yourauthscriptchangeaddress...',
    toAddress: 'nq1recipientauthscriptaddress...'
  });

  try {
    const validity = await assets.checkDepinValidity('&DEVICE/ROUTER001', 'nq1recipientauthscriptaddress...');
    console.log('DEPIN validity for AuthScript address:', validity);

    const holders = await assets.listDepinHolders('&DEVICE/ROUTER001');
    console.log('DEPIN holders:', holders);
  } catch (error) {
    console.error('Error querying DEPIN AuthScript data:', error.message);
  }
}

createDepinForPQAddress();
queryDepinValidityForPQAddress();
